import { defaultTheme as options } from '../../core/defaulttheme';

options.zoom = function(userProp) {
    return {
        enabled: false,
        type: 'xy', // x, y, xy
        minZoom: 1,
        wheelZoom: true,
        pan: true,
        transitionDuration: 1000
    };
};

export var _zoomOptions = options.zoom;
